            group_value = result.metadata[group_by_field]
        else:
            group_value = 'unknown'

        grouped_results[group_value].append(result)

    # Define default aggregation functions if none provided
    if aggregation_funcs is None:
        aggregation_funcs = {
            'count': len,
            'avg_score': lambda results: statistics.mean([r.score for r in results]) if results else 0,
            'max_score': lambda results: max([r.score for r in results]) if results else 0,
            'min_score': lambda results: min([r.score for r in results]) if results else 0
        }

    # Calculate statistics for each group
    aggregated_stats = {}

    for group_value, results in grouped_results.items():
        group_stats = {}

        for stat_name, agg_func in aggregation_funcs.items():
