from typing import List, Dict, Any, Optional
from leann.cli import LeannCLI
from leann.api import LeannBuilder, LeannSearcher
from pathlib import Path

def convert_cli_args_to_api_config(
    args_list: List[str],
    command_type: str = "build"
) -> Dict[str, Any]:
    """Convert CLI arguments to API configuration dictionary.

    Args:
        args_list: List of command line arguments
        command_type: Type of command ('build' or 'search')

    Returns:
        Dictionary containing API configuration extracted from CLI arguments
    """
    # Create CLI instance and parse arguments
    cli = LeannCLI()

    # Add command type as the first argument to simulate CLI invocation
    full_args = [command_type] + args_list

    # Parse the arguments using leann's CLI parser
    parsed_args = cli.parse_args(full_args)

    # Initialize configuration dictionary with common parameters
    config = {
        'command': command_type,
        'index_path': Path(parsed_args.index) if hasattr(parsed_args, 'index') else None,
    }

    # Add command-specific parameters
    if command_type == "build":
        # Handle build command parameters
        if hasattr(parsed_args, 'docs'):
            config['docs_paths'] = [Path(doc) for doc in parsed_args.docs]

        if hasattr(parsed_args, 'chunk_size'):
            config['chunk_size'] = parsed_args.chunk_size

        if hasattr(parsed_args, 'chunk_overlap'):
            config['chunk_overlap'] = parsed_args.chunk_overlap

        if hasattr(parsed_args, 'embedding_model'):
            config['embedding_model'] = parsed_args.embedding_model

        if hasattr(parsed_args, 'vector_store'):
            config['vector_store'] = parsed_args.vector_store

    elif command_type == "search":
        # Handle search command parameters
        if hasattr(parsed_args, 'query'):
            config['query'] = parsed_args.query

        if hasattr(parsed_args, 'top_k'):
            config['top_k'] = parsed_args.top_k

        if hasattr(parsed_args, 'similarity_threshold'):
            config['similarity_threshold'] = parsed_args.similarity_threshold

        if hasattr(parsed_args, 'search_type'):
            config['search_type'] = parsed_args.search_type

    # Add any additional common parameters that might be present
    common_params = ['verbose', 'log_level', 'config_file']
    for param in common_params:
        if hasattr(parsed_args, param):
            config[param] = getattr(parsed_args, param)

    # Remove None values to keep the config clean
    config = {k: v for k, v in config.items() if v is not None}

    return config

